const s = (qty: number, hours: number, cost: number) => ({
  qty, hours,
  upm: hours > 0 ? qty / hours : 0,
  mpu: qty > 0 ? hours / qty : 0,
  uc: qty > 0 ? cost / qty : 0,
  cost,
});
const z = () => s(0, 0, 0);

