// ---------------------------------------------------------------------------
// Build service registry from demo projects
// ---------------------------------------------------------------------------

export function buildDemoRegistry(tenantId: string) {
  return {
    tenantId,
    items: tenantId === 'superior' ? buildSuperiorServices(DEMO_PROJECTION_PROJECTS) : [],
  };
}
